                  <tr key={donation.id} className="hover:bg-stone-50/50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="font-medium text-stone-900">{donation.title}</div>
                      <div className="flex gap-2 mt-1">
                        {donation.tags.map(tag => (
