                    </td>
                    <td className="px-6 py-4 text-stone-600">{donation.weight} kg</td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium border
                        ${donation.status === 'completed' ? 'bg-forest-50 text-forest-700 border-forest-100' : 
                          donation.status === 'assigned' ? 'bg-amber-50 text-amber-700 border-amber-100' :
                          'bg-stone-100 text-stone-600 border-stone-200'}`}>
                        {donation.status === 'completed' && <CheckCircle2 size={12} />}
