import React from 'react';
import { Donation } from '../types';
import { Package, Utensils, Truck, CheckCircle2, Clock, MapPin } from 'lucide-react';
import { findNearbyCharities } from '../services/geminiService';
import { Skeleton } from '../components/ui/Skeleton';

interface DashboardProps {
    donations: Donation[];
}

const Dashboard: React.FC<DashboardProps> = ({ donations }) => {
  const [nearbyCharities, setNearbyCharities] = React.useState<any[]>([]);
  const [groundingLoading, setGroundingLoading] = React.useState(false);

  // Derive stats from donations
  const completedDonations = donations.filter(d => d.status === 'completed');
  const rescuedKg = completedDonations.reduce((acc, curr) => acc + curr.weight, 450); // 450 base
  const mealsServed = Math.floor(rescuedKg * 4);

  const nextPickup = donations.find(d => d.status === 'assigned');

  const recentActivity = [...donations].sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()).slice(0, 5);

  const handleLocateCharities = async () => {
    setGroundingLoading(true);
    try {
        if ("geolocation" in navigator) {
            navigator.geolocation.getCurrentPosition(async (position) => {
                const results = await findNearbyCharities(position.coords.latitude, position.coords.longitude);
                setNearbyCharities(results);
                setGroundingLoading(false);
            }, () => {
                setGroundingLoading(false);
                alert("Could not get location");
            });
        }
    } catch (e) {
        console.error(e);
        setGroundingLoading(false);
    }
  }

  const StatCard = ({ title, value, subtext, icon: Icon }: any) => (
    <div className="bg-white border border-stone-200 p-6 rounded-xl flex items-start justify-between hover:border-forest-200 transition-colors shadow-sm">
      <div>
        <p className="text-stone-500 text-sm font-medium mb-1">{title}</p>
        <h3 className="text-2xl font-bold text-forest-900">{value}</h3>
        {subtext && <p className="text-stone-400 text-xs mt-2 font-medium">{subtext}</p>}
      </div>
      <div className="p-2 bg-stone-50 rounded-lg text-forest-700">
        <Icon size={20} />
      </div>
    </div>
  );

  const StatusBadge = ({ status }: { status: string }) => {
    if (status === 'assigned') {
      return (
        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-amber-50 text-amber-700 border border-amber-100">
          <span className="w-1.5 h-1.5 rounded-full bg-amber-500"></span>
          Assigned
        </span>
      );
    }
    if (status === 'completed') {
      return (
        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-emerald-50 text-emerald-700 border border-emerald-100">
          <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span>
          Completed
        </span>
      );
    }
    return (
      <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-stone-100 text-stone-600 border border-stone-200">
        <span className="w-1.5 h-1.5 rounded-full bg-stone-500"></span>
        Pending
      </span>
    );
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div>
        <h1 className="text-2xl font-semibold text-stone-900 tracking-tight">Good afternoon, Hotel Pritam.</h1>
        <p className="text-stone-500 mt-1">Here's your impact overview for today.</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <StatCard 
          title="Total Food Rescued" 
          value={`${rescuedKg} kg`} 
          subtext="+45 kg this week"
          icon={Package} 
        />
        <StatCard 
          title="Meals Served" 
          value={mealsServed} 
          subtext="~4 meals per kg"
          icon={Utensils} 
        />
        <StatCard 
          title="Next Pickup" 
          value={nextPickup ? nextPickup.pickupWindow : "No pending pickups"} 
          subtext={nextPickup ? `Volunteer: ${nextPickup.assignedVolunteer?.name || 'Assigned'}` : "All clear"}
          icon={Truck} 
        />
      </div>

      {/* Recent Activity Section */}
      <div className="bg-white border border-stone-200 rounded-xl overflow-hidden shadow-sm">
        <div className="px-6 py-4 border-b border-stone-100 flex justify-between items-center">
          <h3 className="font-semibold text-stone-800">Recent Activity</h3>
          <button className="text-sm text-forest-600 hover:text-forest-700 font-medium">View All</button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-stone-50 text-stone-500 font-medium">
              <tr>
                <th className="px-6 py-3">Donation</th>
                <th className="px-6 py-3">Weight</th>
                <th className="px-6 py-3">Status</th>
                <th className="px-6 py-3 text-right">Time</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-stone-100">
              {recentActivity.length === 0 ? (
                  <tr>
                      <td colSpan={4} className="px-6 py-8 text-center text-stone-400">No recent activity</td>
                  </tr>
              ) : (
                recentActivity.map((donation) => (
                  <tr key={donation.id} className="hover:bg-stone-50/50 transition-colors">
