                 </p>

                 {nearbyCharities.length > 0 ? (
                    <div className="grid gap-3 mb-4">
                        {nearbyCharities.map((place, idx) => (
                            <a href={place.uri} target="_blank" rel="noreferrer" key={idx} className="flex items-center justify-between p-3 bg-white rounded-lg border border-forest-100 hover:border-forest-300 transition-colors">
                                <span className="font-medium text-forest-800">{place.name}</span>
