import React, { useState } from 'react';
import { generateImpactVideo } from '../services/geminiService';
import { Video, Loader2, Share2 } from 'lucide-react';
import { Donation } from '../types';

interface HistoryProps {
    donations: Donation[];
}

const History: React.FC<HistoryProps> = ({ donations }) => {
  const [generatingId, setGeneratingId] = useState<string | null>(null);
  const [videos, setVideos] = useState<Record<string, string>>({});

  const historyItems = donations.filter(d => d.status === 'completed');

  const handleGenerateVideo = async (id: string, imageUrl: string) => {
    setGeneratingId(id);
    try {
        // Convert image URL to File object (simulation)
        // Note: this works for local blob URLs or CORS-enabled images.
        const response = await fetch(imageUrl);
        const blob = await response.blob();
        const file = new File([blob], "image.jpg", { type: "image/jpeg" });

        const videoUrl = await generateImpactVideo(file);
        setVideos(prev => ({ ...prev, [id]: videoUrl }));
    } catch (e) {
        console.error(e);
        alert("Video generation failed or was cancelled.");
    } finally {
        setGeneratingId(null);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <h1 className="text-2xl font-semibold text-stone-900">Donation History</h1>

      <div className="grid grid-cols-1 gap-6">
        {historyItems.length === 0 && (
             <div className="text-center py-12 text-stone-400">
                 No completed donations yet.
             </div>
        )}
        {historyItems.map((item) => (
            <div key={item.id} className="bg-white border border-stone-200 rounded-xl overflow-hidden shadow-sm flex flex-col md:flex-row">
                <div className="md:w-48 h-48 md:h-auto relative bg-stone-100">
                   {videos[item.id] ? (
                       <video src={videos[item.id]} controls className="w-full h-full object-cover" />
                   ) : (
                       <img src={item.imageUrl || "https://placehold.co/300x200?text=Food"} alt="Food" className="w-full h-full object-cover" />
                   )}

                   {/* Overlay for generation */}
                   {!videos[item.id] && item.imageUrl && (
                       <div className="absolute inset-0 bg-black/0 hover:bg-black/20 transition-colors flex items-center justify-center group">
                            <button 
                                onClick={() => handleGenerateVideo(item.id, item.imageUrl!)}
                                disabled={!!generatingId}
                                className="opacity-0 group-hover:opacity-100 bg-white text-forest-800 px-4 py-2 rounded-full font-medium shadow-lg transform translate-y-2 group-hover:translate-y-0 transition-all flex items-center gap-2 disabled:opacity-50"
                            >
                                {generatingId === item.id ? <Loader2 size={16} className="animate-spin" /> : <Video size={16} />}
                                {generatingId === item.id ? 'Generating...' : 'Create Impact Video'}
                            </button>
                       </div>
                   )}
                </div>

                <div className="p-6 flex-1 flex flex-col justify-between">
                    <div>
                        <div className="flex justify-between items-start mb-2">
                            <h3 className="font-semibold text-lg text-stone-900">{item.title}</h3>
                            <span className="text-stone-500 text-sm">{item.timestamp}</span>
                        </div>
                        <p className="text-stone-600">Weight: {item.weight} kg</p>
                        <div className="mt-4 flex gap-2">
                             <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-emerald-50 text-emerald-700 border border-emerald-100">
                                <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span>
                                Completed
                             </span>
                             <span className="inline-block px-2 py-1 bg-stone-100 text-stone-600 text-xs rounded border border-stone-200">Verified by Partner</span>
                        </div>
                    </div>

                    {videos[item.id] && (
                        <div className="mt-4 pt-4 border-t border-stone-100 flex gap-3">
                             <button className="text-sm flex items-center gap-2 text-forest-700 font-medium hover:text-forest-800">
                                <Share2 size={16} /> Share on Social
                             </button>
                        </div>
                    )}
                </div>
            </div>
        ))}
      </div>
    </div>
  );
};

