import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Donate from './pages/Donate';
import History from './pages/History';
import Requests from './pages/Requests';
import { NavItem, Donation, Volunteer } from './types';

// Initial Mock Data
const INITIAL_DONATIONS: Donation[] = [
    { 
        id: '1', title: 'Lunch Buffet Leftovers', weight: 12, tags: ['Rice', 'Curry'], 
        status: 'completed', timestamp: '2 hours ago', pickupWindow: '14:00 - 16:00',
        imageUrl: 'https://images.unsplash.com/photo-1555244162-803834f70033?auto=format&fit=crop&q=80&w=400'
    },
    { 
        id: '2', title: 'Breakfast Pastries', weight: 5, tags: ['Bread', 'Dessert'], 
        status: 'assigned', timestamp: 'Today, 10:00 AM', pickupWindow: '10:00 - 12:00',
        assignedVolunteer: { id: 'v1', name: 'Vikram Singh', rating: 4.8, distanceKm: 2.3, etaMinutes: 12, vehicle: 'Tata Ace' }
    }
];

const App: React.FC = () => {
  const [currentTab, setCurrentTab] = useState<NavItem>(NavItem.DASHBOARD);
  const [donations, setDonations] = useState<Donation[]>(INITIAL_DONATIONS);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Computed property for notification badge
  const activeRequestsCount = donations.filter(d => d.status === 'pending' && d.activeRequest).length;

  const handleNavigate = (tab: NavItem) => {
    setEditingId(null);
    setCurrentTab(tab);
  };

  const handleAddDonation = (donationData: Partial<Donation>) => {
      if (editingId) {
          setDonations(prev => prev.map(d => d.id === editingId ? { ...d, ...donationData } : d));
          setEditingId(null);
          setCurrentTab(NavItem.REQUESTS);
      } else {
          const newId = Math.random().toString(36).substr(2, 9);
          const newDonation: Donation = {
              id: newId,
              title: donationData.title || 'Untitled Donation',
              weight: donationData.weight || 0,
              tags: donationData.tags || [],
              status: 'pending',
              timestamp: 'Just now',
              pickupWindow: donationData.pickupWindow || 'Anytime',
              imageUrl: donationData.imageUrl,
              ...donationData
          };

          setDonations(prev => [newDonation, ...prev]);

          // SIMULATION: Automatically get a volunteer request after 3 seconds
          setTimeout(() => {
              simulateIncomingRequest(newId);
          }, 3000);
      }
  };

  const handleEditDonation = (id: string) => {
      setEditingId(id);
      setCurrentTab(NavItem.DONATE);
  };

  const simulateIncomingRequest = (donationId: string) => {
      const mockVolunteer: Volunteer = {
          id: 'v_' + Math.random().toString(36),
          name: 'Rahul Kumar',
          rating: 4.9,
          distanceKm: 3.5,
          etaMinutes: 15,
          vehicle: 'E-Rickshaw'
      };

      setDonations(prev => prev.map(d => {
          if (d.id === donationId && d.status === 'pending') {
              return { ...d, activeRequest: mockVolunteer };
          }
          return d;
      }));
  };

  const handleAcceptRequest = (donationId: string) => {
      setDonations(prev => prev.map(d => {
          if (d.id === donationId && d.activeRequest) {
              return { 
                  ...d, 
                  status: 'assigned', 
                  assignedVolunteer: d.activeRequest,
                  activeRequest: undefined 
              };
          }
          return d;
      }));
  };

  const handleRejectRequest = (donationId: string) => {
      setDonations(prev => prev.map(d => {
          if (d.id === donationId) {
              return { ...d, activeRequest: undefined }; // Remove request, wait for next (simulated)
          }
          return d;
      }));
  };

  const handleCompleteDonation = (donationId: string) => {
      setDonations(prev => prev.map(d => {
          if (d.id === donationId) {
              return { ...d, status: 'completed' };
          }
          return d;
      }));
  };

  const renderContent = () => {
    switch (currentTab) {
      case NavItem.DASHBOARD:
        return <Dashboard donations={donations} />;
      case NavItem.DONATE:
        const initialData = editingId ? donations.find(d => d.id === editingId) : undefined;
        return <Donate onSave={handleAddDonation} initialData={initialData} />;
      case NavItem.REQUESTS:
        return <Requests 
            donations={donations} 
            onAccept={handleAcceptRequest}
            onReject={handleRejectRequest}
            onComplete={handleCompleteDonation}
            onEdit={handleEditDonation}
        />;
      case NavItem.HISTORY:
        return <History donations={donations} />;
      case NavItem.SETTINGS:
        return (
          <div className="p-8 text-stone-500 flex flex-col items-center justify-center h-[50vh]">
            <h2 className="text-lg font-medium text-stone-900 mb-2">Settings</h2>
            <p>Account configuration and preferences would go here.</p>
          </div>
        );
      default:
        return <Dashboard donations={donations} />;
    }
  };

  return (
    <Layout activeTab={currentTab} onNavigate={handleNavigate} notificationCount={activeRequestsCount}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Upload, X, Loader2, Sparkles, Wand2, ArrowRight, CheckCircle } from 'lucide-react';
import { analyzeFoodImage, editFoodImage } from '../services/geminiService';
import { Donation } from '../types';

const AVAILABLE_TAGS = ['Rice', 'Curry', 'Bread', 'Dessert', 'Veg', 'Non-Veg', 'Dairy', 'Fruit'];

interface DonateProps {
    onSave: (donation: Partial<Donation>) => void;
    initialData?: Donation;
}

const Donate: React.FC<DonateProps> = ({ onSave, initialData }) => {
  const [file, setFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(initialData?.imageUrl || null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [editPrompt, setEditPrompt] = useState("");
  const [isSuccess, setIsSuccess] = useState(false);

  // Parse existing time window or default
  const [startT, endT] = initialData?.pickupWindow ? initialData.pickupWindow.split(' - ') : ['16:00', '18:00'];

  // Form State
  const [title, setTitle] = useState(initialData?.title || '');
  const [selectedTags, setSelectedTags] = useState<string[]>(initialData?.tags || []);
  const [quantity, setQuantity] = useState<number>(initialData?.weight || 5);
  const [startTime, setStartTime] = useState(startT);
  const [endTime, setEndTime] = useState(endT);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      const url = URL.createObjectURL(selectedFile);
      setPreviewUrl(url);

      // Auto analyze
      setIsAnalyzing(true);
      try {
        const result = await analyzeFoodImage(selectedFile);
        setTitle(result.title);
        // Merge tags
        const newTags = new Set([...selectedTags, ...result.tags.filter((t: string) => AVAILABLE_TAGS.includes(t))]);
        setSelectedTags(Array.from(newTags));
        if (result.weightEstimate) setQuantity(result.weightEstimate);
      } catch (err) {
        console.error("Analysis failed", err);
      } finally {
        setIsAnalyzing(false);
      }
    }
  };

  const handleEditImage = async () => {
    if (!file || !editPrompt) return;
    setIsEditing(true);
    try {
        const newImageUrl = await editFoodImage(file, editPrompt);
        setPreviewUrl(newImageUrl);
        setEditPrompt("");
    } catch (e) {
        console.error("Edit failed", e);
        alert("Failed to edit image");
    } finally {
        setIsEditing(false);
    }
  }

  const toggleTag = (tag: string) => {
    if (selectedTags.includes(tag)) {
      setSelectedTags(selectedTags.filter(t => t !== tag));
    } else {
      setSelectedTags([...selectedTags, tag]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Construct new donation object
    const newDonation: Partial<Donation> = {
        title,
        weight: quantity,
        tags: selectedTags,
        pickupWindow: `${startTime} - ${endTime}`,
        imageUrl: previewUrl || undefined,
        // Only add timestamp if creating fresh, but simpler to leave undefined and let App handle logic
        // or just let it update 'Just now' if it's new.
    };

    onSave(newDonation);
    setIsSuccess(true);
  };

  if (isSuccess) {
      return (
          <div className="flex flex-col items-center justify-center h-[60vh] text-center animate-in fade-in zoom-in duration-500">
              <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6">
                  <CheckCircle size={40} />
              </div>
              <h2 className="text-2xl font-bold text-stone-900 mb-2">{initialData ? 'Donation Updated!' : 'Donation Broadcasted!'}</h2>
              <p className="text-stone-500 max-w-md mb-8">
                  {initialData 
                    ? 'Your changes have been saved and partners have been notified.' 
                    : 'Your food availability has been sent to nearby partners.'} 
                  <br />
                  Go to the <strong>My Donations</strong> tab to manage requests.
              </p>
          </div>
      );
  }

  return (
    <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 max-w-2xl mx-auto">
      <div className="mb-6">
        <h1 className="text-2xl font-semibold text-stone-900">{initialData ? 'Edit Donation' : 'Post New Donation'}</h1>
        <p className="text-stone-500">{initialData ? 'Update details below.' : 'Details broadcast to partners immediately.'}</p>
      </div>

      <form onSubmit={handleSubmit} className="bg-white border border-stone-200 rounded-xl p-6 md:p-8 shadow-sm space-y-8">

        {/* Image Section */}
        <div className="space-y-4">
          <label className="block text-sm font-medium text-stone-700">Food Image</label>

          {!previewUrl ? (
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="border-2 border-dashed border-stone-200 rounded-xl p-8 flex flex-col items-center justify-center text-stone-400 hover:border-forest-400 hover:bg-forest-50 transition-colors cursor-pointer h-48"
            >
              <Upload size={32} className="mb-2" />
              <p className="text-sm font-medium">Click to upload or drag & drop</p>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileSelect} 
                className="hidden" 
                accept="image/*"
              />
            </div>
          ) : (
            <div className="relative rounded-xl overflow-hidden bg-stone-100 border border-stone-200">
               <img src={previewUrl} alt="Preview" className="w-full h-64 object-cover" />

               {/* Image Actions Overlay */}
               <div className="absolute top-2 right-2 flex gap-2">
                 <button 
                   type="button"
                   onClick={() => {
                     setFile(null);
                     setPreviewUrl(null);
                     setTitle('');
                     setSelectedTags([]);
                   }}
                   className="p-1.5 bg-white/90 backdrop-blur text-stone-600 rounded-full hover:text-red-600 shadow-sm"
                 >
                   <X size={16} />
                 </button>
               </div>

               {isAnalyzing && (
                 <div className="absolute inset-0 bg-white/80 backdrop-blur-sm flex items-center justify-center flex-col gap-2 text-forest-700">
                    <Loader2 size={32} className="animate-spin" />
                    <span className="text-sm font-medium">Analyzing food with Gemini...</span>
                 </div>
               )}

               {/* Magic Edit Bar */}
               <div className="absolute bottom-0 inset-x-0 bg-white/95 border-t border-stone-200 p-3 flex gap-2 items-center">
                  <Wand2 size={16} className="text-forest-600" />
                  <input 
                    type="text" 
                    value={editPrompt}
                    onChange={(e) => setEditPrompt(e.target.value)}
                    placeholder="Ask Gemini to edit... (e.g. 'Remove background')"
                    className="flex-1 bg-transparent text-sm focus:outline-none placeholder:text-stone-400"
                  />
                  <button 
                    type="button"
                    onClick={handleEditImage}
                    disabled={!editPrompt || isEditing}
                    className="text-xs bg-stone-900 text-white px-3 py-1.5 rounded-md hover:bg-stone-800 disabled:opacity-50"
                  >
                    {isEditing ? 'Editing...' : 'Apply'}
                  </button>
               </div>
            </div>
          )}
        </div>

        {/* Title */}
        <div>
          <label className="block text-sm font-medium text-stone-700 mb-1.5">Food Title</label>
          <div className="relative">
             <input
                type="text"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="e.g. Lunch Buffet Leftovers"
                className="w-full px-4 py-2.5 rounded-lg border border-stone-200 focus:outline-none focus:ring-2 focus:ring-forest-500/20 focus:border-forest-500 transition-all placeholder:text-stone-400"
                required
            />
            {isAnalyzing && <Sparkles size={16} className="absolute right-3 top-3 text-forest-500 animate-pulse" />}
          </div>
        </div>

        {/* Tags */}
        <div>
          <label className="block text-sm font-medium text-stone-700 mb-2">Food Type</label>
          <div className="flex flex-wrap gap-2">
            {AVAILABLE_TAGS.map(tag => (
              <button
                key={tag}
                type="button"
                onClick={() => toggleTag(tag)}
                className={`px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 border
                  ${selectedTags.includes(tag)
                    ? 'bg-forest-600 text-white border-forest-600 shadow-sm scale-105'
                    : 'bg-white text-stone-600 border-stone-200 hover:border-forest-300 hover:text-forest-700'
                  }`}
              >
                {tag}
              </button>
            ))}
          </div>
        </div>

        {/* Quantity */}
        <div>
          <label className="block text-sm font-medium text-stone-700 mb-2">Estimated Quantity (kg)</label>
          <div className="flex items-center gap-4">
             <input 
               type="range" 
               min="1" 
               max="50" 
               value={quantity} 
               onChange={(e) => setQuantity(parseInt(e.target.value))}
               className="flex-1 accent-forest-600 h-2 bg-stone-100 rounded-lg appearance-none cursor-pointer"
             />
             <div className="w-20">
               <input
                 type="number"
                 value={quantity}
                 onChange={(e) => setQuantity(parseInt(e.target.value))}
                 className="w-full px-3 py-2 text-center rounded-lg border border-stone-200 focus:outline-none focus:border-forest-500 font-semibold text-stone-800"
               />
             </div>
          </div>
        </div>

        {/* Time Window */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-stone-700 mb-1.5">Pickup Start</label>
            <input
              type="time"
              value={startTime}
              onChange={(e) => setStartTime(e.target.value)}
              className="w-full px-4 py-2.5 rounded-lg border border-stone-200 focus:outline-none focus:border-forest-500"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-stone-700 mb-1.5">Pickup End</label>
            <input
              type="time"
              value={endTime}
              onChange={(e) => setEndTime(e.target.value)}
              className="w-full px-4 py-2.5 rounded-lg border border-stone-200 focus:outline-none focus:border-forest-500"
            />
          </div>
        </div>

        <button
          type="submit"
          className="w-full bg-forest-700 text-white font-medium py-3 rounded-lg hover:bg-forest-800 transition-colors shadow-sm flex items-center justify-center gap-2 active:scale-[0.99]"
        >
          {initialData ? 'Update Donation' : 'Broadcast Availability'}
          <ArrowRight size={18} />
        </button>

      </form>
    </div>
  );
};

export default Donate;

