import React, { useState } from 'react';
import { Donation, Volunteer, TrackingInfo } from '../types';
import { Clock, MapPin, User, Star, Check, X, Phone, ShieldCheck, CheckCircle2, Loader2, Pencil, Info, Calendar, Award, PhoneCall, Navigation, AlertTriangle } from 'lucide-react';

interface RequestsProps {
  donations: Donation[];
  onAccept: (donationId: string) => void;
  onReject: (donationId: string) => void;
  onComplete: (donationId: string) => void;
  onEdit: (donationId: string) => void;
}

const Requests: React.FC<RequestsProps> = ({ donations, onAccept, onReject, onComplete, onEdit }) => {
  const [selectedVolunteer, setSelectedVolunteer] = useState<Volunteer | null>(null);
  const [trackingDonation, setTrackingDonation] = useState<Donation | null>(null);

  const activeDonations = donations.filter(d => d.status !== 'completed');

  const StatusBadge = ({ status }: { status: 'pending' | 'assigned' | 'completed' }) => {
    if (status === 'assigned') {
      return (
        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-amber-50 text-amber-700 border border-amber-100">
          <span className="w-1.5 h-1.5 rounded-full bg-amber-500"></span>
          Assigned
        </span>
      );
    }
    if (status === 'completed') {
      return (
        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-emerald-50 text-emerald-700 border border-emerald-100">
          <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span>
          Completed
        </span>
      );
    }
    return (
      <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-stone-100 text-stone-600 border border-stone-200">
        <span className="w-1.5 h-1.5 rounded-full bg-stone-500"></span>
        Pending
      </span>
    );
  };

  const TrackingMap = ({ tracking }: { tracking: TrackingInfo }) => {
      const isDeviated = tracking.status === 'deviated';
      // Calculate SVG positions based on progress
      // Start (10, 50) -> End (90, 50)
      const startX = 10;
      const endX = 90;
      const currentX = startX + ((endX - startX) * (tracking.progress / 100));
      const currentY = isDeviated ? 30 : 50; // Deviate upwards if off route

      return (
          <div className="relative w-full h-48 bg-stone-100 rounded-xl overflow-hidden border border-stone-200">
              {/* Map Grid Pattern */}
              <div className="absolute inset-0 opacity-10" 
                  style={{ backgroundImage: 'radial-gradient(#444 1px, transparent 1px)', backgroundSize: '20px 20px' }}>
              </div>

              <svg className="w-full h-full" viewBox="0 0 100 100" preserveAspectRatio="none">
                  {/* Route Line */}
                  <line x1="10" y1="50" x2="90" y2="50" stroke="#d6d3d1" strokeWidth="2" strokeDasharray="4 2" />

                  {/* Progress Line */}
                  <line x1="10" y1="50" x2={currentX} y2="50" stroke="#059669" strokeWidth="2" />

                  {/* Deviation Line (if applicable) */}
                  {isDeviated && (
                      <line x1={currentX} y1="50" x2={currentX} y2="30" stroke="#ef4444" strokeWidth="1" strokeDasharray="2 2" />
                  )}

                  {/* Start Point */}
                  <circle cx="10" cy="50" r="3" fill="#292524" />

                  {/* End Point */}
                  <circle cx="90" cy="50" r="3" fill="#292524" />

                  {/* Vehicle */}
                  <g transform={`translate(${currentX}, ${currentY})`}>
                      <circle cx="0" cy="0" r="4" fill={isDeviated ? "#ef4444" : "#059669"} stroke="white" strokeWidth="2" className="transition-all duration-1000 ease-linear" />
                      {/* Pulse effect */}
                      <circle cx="0" cy="0" r="8" fill={isDeviated ? "#ef4444" : "#059669"} opacity="0.2" className="animate-ping" />
                  </g>
              </svg>

              {/* Labels */}
              <div className="absolute top-1/2 left-2 transform -translate-y-1/2 mt-4 text-[10px] font-bold text-stone-600">HOTEL</div>
              <div className="absolute top-1/2 right-2 transform -translate-y-1/2 mt-4 text-[10px] font-bold text-stone-600">DESTINATION</div>

              {/* Status Overlay */}
               <div className="absolute top-3 right-3">
                  {isDeviated ? (
                      <span className="bg-red-100 text-red-700 text-xs font-bold px-2 py-1 rounded-md border border-red-200 flex items-center gap-1">
                          <AlertTriangle size={12} /> Route Deviation Detected
                      </span>
                  ) : (
                      <span className="bg-green-100 text-green-700 text-xs font-bold px-2 py-1 rounded-md border border-green-200 flex items-center gap-1">
                          <Navigation size={12} /> On Route
                      </span>
                  )}
               </div>
          </div>
      );
  }

  if (activeDonations.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-[50vh] text-stone-500">
        <div className="bg-stone-100 p-4 rounded-full mb-4">
          <CheckCircle2 size={32} />
        </div>
        <p className="text-lg font-medium text-stone-900">No active requests</p>
        <p className="max-w-xs text-center mt-2">Post a new donation to start receiving requests from volunteers.</p>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500 relative">
      <div>
        <h1 className="text-2xl font-semibold text-stone-900">My Donations</h1>
        <p className="text-stone-500 mt-1">Manage pickups and volunteer assignments.</p>
      </div>

      <div className="grid gap-6">
        {activeDonations.map(donation => (
          <div key={donation.id} className="bg-white border border-stone-200 rounded-xl overflow-hidden shadow-sm hover:border-forest-200 transition-colors">

            {/* Donation Header */}
            <div className="p-6 border-b border-stone-100 flex justify-between items-start">
              <div className="flex gap-4">
                 {donation.imageUrl ? (
                     <img src={donation.imageUrl} alt={donation.title} className="w-20 h-20 rounded-lg object-cover bg-stone-100" />
                 ) : (
                     <div className="w-20 h-20 bg-stone-100 rounded-lg flex items-center justify-center text-stone-400">
                        <User size={24} />
                     </div>
                 )}
                 <div>
                    <h3 className="font-semibold text-lg text-stone-900">{donation.title}</h3>
                    <div className="flex flex-wrap gap-2 mt-2">
                        <span className="text-xs font-medium px-2 py-1 bg-stone-100 text-stone-600 rounded-md">
                            {donation.weight} kg
                        </span>
                        <span className="text-xs font-medium px-2 py-1 bg-stone-100 text-stone-600 rounded-md flex items-center gap-1">
                            <Clock size={12} /> {donation.pickupWindow}
                        </span>
                        {donation.tags.map(tag => (
                            <span key={tag} className="text-xs px-2 py-1 bg-stone-50 text-stone-500 border border-stone-100 rounded-md">
                                {tag}
                            </span>
                        ))}
                    </div>
                 </div>
              </div>
              <div className="flex flex-col items-end gap-2">
                  <StatusBadge status={donation.status} />
                  {donation.status !== 'completed' && (
                    <button 
                        onClick={() => onEdit(donation.id)}
                        className="text-xs font-medium text-stone-500 hover:text-forest-700 flex items-center gap-1 px-2 py-1 rounded hover:bg-stone-50 transition-colors"
                    >
                        <Pencil size={12} />
                        Edit
                    </button>
                  )}
              </div>
            </div>

            {/* Request / Volunteer Section */}
            <div className="bg-stone-50/50 p-6">
                {donation.assignedVolunteer ? (
                    // ASSIGNED STATE
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 bg-forest-100 rounded-full flex items-center justify-center text-forest-700 font-bold text-xl">
                                {donation.assignedVolunteer.name[0]}
                            </div>
                            <div>
                                <h4 className="font-medium text-stone-900">{donation.assignedVolunteer.name} is on the way</h4>
                                <div className="flex items-center gap-3 text-sm text-stone-500 mt-1">
                                    <span className="flex items-center gap-1"><Star size={14} className="text-amber-400 fill-amber-400"/> {donation.assignedVolunteer.rating}</span>
                                    <span>•</span>
                                    <span>{donation.assignedVolunteer.vehicle}</span>
                                    <span>•</span>
                                    <span className="text-forest-600 font-medium">ETA: {donation.assignedVolunteer.etaMinutes} mins</span>
                                </div>
                            </div>
                        </div>
                        <div className="flex gap-3 items-center">
                            {/* NEW: Live Track Button */}
                            {donation.tracking && donation.status !== 'completed' && (
                                <button
                                    onClick={() => setTrackingDonation(donation)}
                                    className="text-sm font-medium text-forest-700 bg-forest-50 border border-forest-100 hover:bg-forest-100 px-3 py-2 rounded-lg transition-colors flex items-center gap-1 animate-pulse"
                                >
                                    <Navigation size={16} />
                                    Live Track
                                </button>
                            )}

                             <button 
                                onClick={() => setSelectedVolunteer(donation.assignedVolunteer!)}
                                className="text-sm font-medium text-stone-500 hover:text-forest-700 px-3 py-2 rounded-lg hover:bg-stone-200 transition-colors flex items-center gap-1"
                             >
                                <Info size={16} />
                                Details
                             </button>
                             <button className="p-2 text-stone-500 hover:text-stone-900 hover:bg-stone-200 rounded-full transition-colors" title="Call Driver">
                                 <Phone size={20} />
                             </button>
                             <button 
                                onClick={() => onComplete(donation.id)}
                                className="bg-forest-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-forest-700 transition-colors flex items-center gap-2"
                             >
                                <CheckCircle2 size={16} />
