                    </div>
                ) : donation.activeRequest ? (
                    // PENDING REQUEST STATE
                    <div>
                        <div className="flex items-center gap-2 mb-4">
                            <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></div>
                            <span className="text-sm font-medium text-stone-900">New Request Received</span>
                        </div>
                        <div className="bg-white border border-forest-100 rounded-xl p-4 flex flex-col sm:flex-row justify-between items-center gap-4 shadow-sm">
                            <div className="flex items-center gap-4 w-full sm:w-auto">
                                <div className="w-12 h-12 bg-stone-100 rounded-full flex items-center justify-center text-stone-500">
                                    <User size={24} />
                                </div>
                                <div>
                                    <div className="flex items-center gap-2">
                                        <h4 className="font-semibold text-stone-900">{donation.activeRequest.name}</h4>
                                        <ShieldCheck size={14} className="text-forest-500" />
                                    </div>
                                    <div className="flex items-center gap-3 text-sm text-stone-500 mt-1">
                                        <span className="flex items-center gap-1"><Star size={12} className="text-amber-400 fill-amber-400"/> {donation.activeRequest.rating}</span>
                                        <span>•</span>
                                        <span className="flex items-center gap-1"><MapPin size={12}/> {donation.activeRequest.distanceKm} km away</span>
                                        <span>•</span>
                                        <span>{donation.activeRequest.vehicle}</span>
                                    </div>
                                </div>
                            </div>

                            <div className="flex gap-3 w-full sm:w-auto">
                                <button 
                                    onClick={() => onReject(donation.id)}
                                    className="flex-1 sm:flex-none px-4 py-2 rounded-lg border border-stone-200 text-stone-600 text-sm font-medium hover:bg-stone-50 transition-colors"
                                >
                                    Decline
                                </button>
                                <button 
                                    onClick={() => onAccept(donation.id)}
