                                  <span className="font-medium text-forest-700">100% Adherence</span>
                              </div>
                              <div className="flex justify-between">
                                  <span>Current Speed</span>
                                  <span className="font-medium text-stone-900">32 km/h</span>
                              </div>
                              <div className="flex justify-between">
                                  <span>Last Update</span>
