import React, { useEffect, useRef, useState } from 'react';
import { TrackingInfo } from '../types';

interface LiveMapProps {
  tracking: TrackingInfo;
}

// Minimal Map Style to match the app aesthetic (Desaturated/Earthy)
const MAP_STYLES = [
  {
    "featureType": "all",
    "elementType": "geometry",
    "stylers": [{ "color": "#f5f5f4" }] // stone-100
  },
  {
    "featureType": "all",
    "elementType": "labels.text.fill",
    "stylers": [{ "gamma": 0.01 }, { "lightness": 20 }]
  },
  {
    "featureType": "all",
    "elementType": "labels.text.stroke",
    "stylers": [{ "saturation": -31 }, { "lightness": -33 }, { "weight": 2 }, { "gamma": 0.8 }]
  },
  {
    "featureType": "all",
    "elementType": "labels.icon",
    "stylers": [{ "visibility": "off" }]
  },
  {
    "featureType": "landscape",
    "elementType": "geometry",
    "stylers": [{ "lightness": 30 }, { "saturation": 30 }]
  },
  {
    "featureType": "poi",
    "elementType": "geometry",
    "stylers": [{ "saturation": 20 }]
  },
  {
    "featureType": "poi.park",
    "elementType": "geometry",
    "stylers": [{ "lightness": 20 }, { "saturation": -20 }]
  },
  {
    "featureType": "road",
    "elementType": "geometry",
    "stylers": [{ "lightness": 10 }, { "saturation": -30 }]
  },
  {
    "featureType": "road",
    "elementType": "geometry.stroke",
    "stylers": [{ "saturation": 25 }, { "lightness": 25 }]
  },
  {
    "featureType": "water",
    "elementType": "all",
    "stylers": [{ "lightness": -20 }, { "color": "#c3efd2" }] // forest-200ish
  }
];

const LiveMap: React.FC<LiveMapProps> = ({ tracking }) => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<google.maps.Map | null>(null);
  const markerRef = useRef<google.maps.Marker | null>(null);
  const directionsRendererRef = useRef<google.maps.DirectionsRenderer | null>(null);
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    // Check if Google Maps script is loaded
    if (!window.google || !window.google.maps) {
        // In a real app, you might want a more robust loader, 
        // but index.html script tag usually handles this.
        const checkGoogle = setInterval(() => {
            if (window.google && window.google.maps) {
                clearInterval(checkGoogle);
                setIsLoaded(true);
            }
        }, 500);
        return () => clearInterval(checkGoogle);
    } else {
        setIsLoaded(true);
    }
  }, []);

  // Initialize Map
  useEffect(() => {
    if (isLoaded && mapRef.current && !mapInstanceRef.current) {
        const { lat, lng } = tracking.currentLocation;

        const map = new google.maps.Map(mapRef.current, {
            center: { lat, lng },
            zoom: 14,
            disableDefaultUI: true, // Clean look
            styles: MAP_STYLES,
        });

        mapInstanceRef.current = map;

        // Origin Marker (Hotel)
        new google.maps.Marker({
            position: { lat: 28.6139, lng: 77.2090 }, // Hardcoded Origin for demo matching App.tsx
            map: map,
            icon: {
                path: google.maps.SymbolPath.CIRCLE,
                scale: 8,
                fillColor: "#44403c", // stone-700
                fillOpacity: 1,
                strokeWeight: 2,
                strokeColor: "#ffffff",
            },
            title: "Hotel Pritam"
        });

        // Destination Marker
        new google.maps.Marker({
            position: { lat: tracking.destination.lat, lng: tracking.destination.lng },
            map: map,
            icon: {
                path: google.maps.SymbolPath.CIRCLE,
                scale: 8,
                fillColor: "#44403c",
                fillOpacity: 1,
                strokeWeight: 2,
                strokeColor: "#ffffff",
            },
            title: "Destination"
        });

        // Volunteer Marker (The Truck)
        markerRef.current = new google.maps.Marker({
            position: { lat, lng },
            map: map,
            icon: {
                path: google.maps.SymbolPath.FORWARD_CLOSED_ARROW,
                scale: 6,
                fillColor: "#206e4a", // forest-700
                fillOpacity: 1,
                strokeWeight: 2,
                strokeColor: "#ffffff",
                rotation: 0,
            },
            title: "Volunteer"
        });

        // Directions Renderer
        directionsRendererRef.current = new google.maps.DirectionsRenderer({
            map: map,
            suppressMarkers: true,
            polylineOptions: {
                strokeColor: "#268a5b", // forest-600
                strokeOpacity: 0.6,
                strokeWeight: 4,
            }
        });

        // Calculate Route
        const directionsService = new google.maps.DirectionsService();
        directionsService.route(
            {
                origin: { lat: 28.6139, lng: 77.2090 }, // Origin
                destination: { lat: tracking.destination.lat, lng: tracking.destination.lng },
                travelMode: google.maps.TravelMode.DRIVING,
            },
            (result, status) => {
                if (status === 'OK' && directionsRendererRef.current) {
                    directionsRendererRef.current.setDirections(result);
                }
            }
        );
    }
  }, [isLoaded]);

  // Update Volunteer Position
  useEffect(() => {
    if (mapInstanceRef.current && markerRef.current) {
        const { lat, lng } = tracking.currentLocation;
        const newPos = new google.maps.LatLng(lat, lng);
        markerRef.current.setPosition(newPos);

        // Optional: Pan map to follow if we wanted strict following
        // mapInstanceRef.current.panTo(newPos);

        // Calculate rotation/heading based on interpolation in a real app
        // For this demo, we assume the arrow points generally towards destination or just forward
    }
  }, [tracking]);

  return (
    <div className="relative w-full h-64 bg-stone-100 rounded-xl overflow-hidden border border-stone-200">
        {!isLoaded && (
            <div className="absolute inset-0 flex items-center justify-center text-stone-400">
                Loading Maps...
            </div>
        )}
        <div ref={mapRef} className="w-full h-full" />
    </div>
  );
};

export default LiveMap;

